class Solution:
    def countGoodSubarrays(self, nums):
        n = len(nums)
        cnt = 0
        for l in range(n):
            cur = 0
            present = {}
            for r in range(l, n):
                cur |= nums[r]
                present[nums[r]] = present.get(nums[r], 0) + 1
                if cur in present:
                    cnt += 1
        return cnt

