class Solution:
    def countGoodSubarrays(self, nums):
        n = len(nums)
        last_seen = {}
        groups = []
        total = 0
        for r in range(n):
            last_seen[nums[r]] = r
            new_groups = []
            cur_val, cur_lo, cur_hi = nums[r], r, r
            for val, l_lo, l_hi in groups:
                nv = val | nums[r]
                if nv == cur_val:
                    cur_lo = l_lo
                else:
                    new_groups.append((cur_val, cur_lo, cur_hi))
                    cur_val, cur_lo, cur_hi = nv, l_lo, l_hi
            new_groups.append((cur_val, cur_lo, cur_hi))
            groups = new_groups
            for val, l_lo, l_hi in groups:
                pos = last_seen.get(val, -1)
                if pos < l_lo:
                    continue
                hi = min(l_hi, pos)
                if hi >= l_lo:
                    total += hi - l_lo + 1
        return total

