var countGoodSubarrays = function(nums) {
    const n = nums.length;
    const lastSeen = new Map();
    let groups = [];
    let total = 0;
    for (let r = 0; r < n; r++) {
        lastSeen.set(nums[r], r);
        const newGroups = [];
        let curVal = nums[r], curLo = r, curHi = r;
        for (const [val, lLo, lHi] of groups) {
            const nv = val | nums[r];
            if (nv === curVal) {
                curLo = lLo;
            } else {
                newGroups.push([curVal, curLo, curHi]);
                curVal = nv; curLo = lLo; curHi = lHi;
            }
        }
        newGroups.push([curVal, curLo, curHi]);
        groups = newGroups;
        for (const [val, lLo, lHi] of groups) {
            const pos = lastSeen.has(val) ? lastSeen.get(val) : -1;
            if (pos < lLo) continue;
            const hi = Math.min(lHi, pos);
            if (hi >= lLo) total += hi - lLo + 1;
        }
    }
    return total;
};
